/* ------------------------------------------------------------------ */
/*  Seed function                                                      */
/* ------------------------------------------------------------------ */

export async function seedPhones(): Promise<{
  brands: number;
  phones: number;
  specs: number;
  benchmarks: number;
  prices: number;
  skipped: number;
}> {
  await connectDB();

  let brands = 0;
  let phones = 0;
  let specs = 0;
  let benchmarks = 0;
  let prices = 0;
  let skipped = 0;

  /* ---- 1. Upsert brands ---- */
  const brandMap = new Map<string, Types.ObjectId>();

  for (const b of BRANDS) {
    const doc = await (Brand as any).findOneAndUpdate(
      { slug: b.slug },
      {
        name: b.name,
        slug: b.slug,
        logo: '',
        country: b.country,
        description: b.description,
        sortOrder: b.sortOrder,
        active: true,
      },
      { upsert: true, new: true, setDefaultsOnInsert: true },
    );
    brandMap.set(b.name, doc._id as Types.ObjectId);
    brands++;
  }

  /* ---- 2. Upsert phones + related docs ---- */
  for (const p of PHONES) {
    const brandId = brandMap.get(p.brand);
    if (!brandId) {
      console.warn(`[seed] Skipping "${p.modelName}" — brand "${p.brand}" not found`);
      skipped++;
      continue;
    }

    // Upsert phone
    const phoneDoc = await (Phone as any).findOneAndUpdate(
      { slug: p.slug },
      {
        brandId,
        modelName: p.modelName,
        slug: p.slug,
        releaseDate: p.releaseDate,
        pricePKR: p.pricePKR,
        ptaStatus: p.ptaStatus,
        ptaApproved: p.ptaStatus === 'PTA Approved',
        featured: p.featured,
        trending: p.trending,
        upcoming: p.upcoming,
        thumbnail: '',
        description: p.description,
        cameraScore: p.cameraScore,
        performanceScore: p.performanceScore,
        batteryScore: p.batteryScore,
        displayScore: p.displayScore,
        valueScore: p.valueScore,
        overallRating: p.overallRating,
        active: true,
        status: 'published',
        pros: p.pros,
        cons: p.cons,
        reviewSummary: p.reviewSummary,
        reviewVerdict: p.reviewVerdict,
      },
      { upsert: true, new: true, setDefaultsOnInsert: true },
    );
    phones++;

    const phoneId = phoneDoc._id as Types.ObjectId;

    // Upsert specs
    const specsData: Record<string, string> = {};
    for (const [key, val] of Object.entries(p.specs)) {
      specsData[key] = (val as string) ?? '';
    }
    await (PhoneSpecs as any).findOneAndUpdate(
      { phoneId },
      { phoneId, ...specsData },
      { upsert: true, new: true, setDefaultsOnInsert: true },
    );
    specs++;

    // Upsert benchmark
    if (p.benchmarks) {
      await (PhoneBenchmark as any).findOneAndUpdate(
        { phoneId },
        {
          phoneId,
          antutu: p.benchmarks.antutu ?? 0,
          geekbenchSingle: p.benchmarks.geekbenchSingle ?? 0,
          geekbenchMulti: p.benchmarks.geekbenchMulti ?? 0,
          gamingScore: p.benchmarks.gamingScore ?? 0,
          pubgFps: p.benchmarks.pubgFps ?? '',
          codMobileFps: p.benchmarks.codMobileFps ?? '',
          genshinFps: p.benchmarks.genshinFps ?? '',
          videoPlayback: p.benchmarks.videoPlayback ?? '',
          gamingBattery: p.benchmarks.gamingBattery ?? '',
          browsingBattery: p.benchmarks.browsingBattery ?? '',
        },
        { upsert: true, new: true, setDefaultsOnInsert: true },
      );
      benchmarks++;
    }

    // Handle prices: delete old, insert new
    if (p.prices && p.prices.length > 0) {
      await PhonePrice.deleteMany({ phoneId });
      const priceDocs = p.prices.map((pr) => ({
        phoneId,
        storeName: pr.storeName,
        price: pr.price,
        url: '',
        inStock: pr.inStock ?? true,
      }));
      const inserted = await PhonePrice.insertMany(priceDocs as any);
      prices += inserted.length;
    }
  }

  const summary = { brands, phones, specs, benchmarks, prices, skipped };
  console.log('[seedPhones] Done:', JSON.stringify(summary, null, 2));
  return summary;
}